mapper.select:
SELECT e.id, e.entry_no, e.profile_id, e.user_id, e.employee_no, e.entry_type, e.process_type, e.entry_date, e.dept_id, d.name as dept_name, e.post_ids, e.job_title, e.extension, e.office_location, e.work_location_id, e.direct_supervisor_id, supervisor.name as direct_supervisor_name, e.employment_type, e.probation_months, e.contract_type, e.contract_start_date, e.contract_end_date, e.work_status, e.onboarding_status, e.process_instance_id, e.leave_date, e.leave_reason, e.cancel_reason, e.bank_name, e.bank_branch, e.bank_account, e.account_name, e.remark, e.create_time, e.update_time,
p.name as employee_name, p.mobile, p.email, p.gender, p.id_number, p.birth_date, p.age, p.nationality, p.ethnicity, p.political_status, p.marital_status, p.hometown, p.address, p.emergency_contact, p.emergency_phone FROM hr_employee_entry e LEFT JOIN hr_employee_profile p ON e.profile_id = p.id LEFT JOIN system_dept d ON e.dept_id = d.id LEFT JOIN hr_employee_profile supervisor ON e.direct_supervisor_id = supervisor.id
e.deleted = 0
AND e.entry_no LIKE CONCAT('%', #{ew.entryNo}, '%')
AND e.employee_no LIKE CONCAT('%', #{ew.employeeNo}, '%')
AND e.profile_id = #{ew.profileId}
AND p.name LIKE CONCAT('%', #{ew.employeeName}, '%')
AND p.mobile LIKE CONCAT('%', #{ew.mobile}, '%')
AND e.entry_type = #{ew.entryType}
AND e.process_type = #{ew.processType}
AND e.entry_date = #{ew.entryDate}
AND e.dept_id = #{ew.deptId}
AND e.job_title LIKE CONCAT('%', #{ew.jobTitle}, '%')
AND e.employment_type = #{ew.employmentType}
AND e.contract_type = #{ew.contractType}
AND e.work_status = #{ew.workStatus}
AND e.onboarding_status = #{ew.onboardingStatus}
AND e.bank_name LIKE CONCAT('%', #{ew.bankName}, '%')
AND e.account_name LIKE CONCAT('%', #{ew.accountName}, '%')
AND e.remark LIKE CONCAT('%', #{ew.remark}, '%')
AND e.create_time BETWEEN #{ew.createTime[0]} AND #{ew.createTime[1]}
ORDER BY e.id DESC
